import React from 'react';
import { motion } from 'framer-motion';
import { useUser } from '../hooks/useUser';

const Home: React.FC = () => {
  const { user } = useUser();
  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="page"
    >
      <div className="welcome-banner">
        <h1>Добро пожаловать, {user?.first_name || 'Cadimurx'}!</h1>
        <p>Ежедневный бонус готов к получению</p>
        <button className="bonus-button">Забрать 🎁</button>
      </div>
      {/* Здесь можно добавить последние события, акции и т.д. */}
    </motion.div>
  );
};

export default Home;
